class Solution:
    def shortestSubarray(self, nums, k):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        best = n + 1
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                if s >= k:
                    best = min(best, j - i + 1)
                    break
        return best if best <= n else -1

